// ─────────────────────────────────────────────────────────────────────────────
// Job Knowledge expansion (round 2) — doubles the Job Knowledge bank.
//
// Deeper coverage across all JK topics at CompTIA A+/Network+/Security+ level,
// applied to an embassy IT environment. Authored 2026-06-20 to complement the
// base set (seed.ts) and round 1 (seed-extra.ts).
// ─────────────────────────────────────────────────────────────────────────────

export const JOB_KNOWLEDGE_EXTRA_2 = [
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"EASY","prompt":"A technician at the embassy needs to allow secure, encrypted remote command-line administration of a Linux server. Which default port must be open on the firewall?","options":[{"id":"A","text":"22"},{"id":"B","text":"23"},{"id":"C","text":"80"},{"id":"D","text":"3389"}],"correctId":"A","rationale":"SSH (Secure Shell) uses TCP port 22 and provides encrypted remote command-line access, making it the standard for secure Linux administration. Telnet (23) offers similar remote access but sends data in cleartext and is insecure. Port 80 is HTTP and 3389 is RDP (Windows remote desktop), neither of which is the Linux CLI standard.","optionNotes":{"B":"Telnet (23) is unencrypted cleartext and should not be used","C":"Port 80 is HTTP web traffic, not remote administration","D":"3389 is RDP for Windows graphical remote desktop"},"reference":"IT & Telecommunications › Common port numbers"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"EASY","prompt":"An embassy laptop fails to reach a DHCP server and self-assigns an address in the 169.254.x.x range. What is this address called?","options":[{"id":"A","text":"An APIPA (link-local) address"},{"id":"B","text":"A loopback address"},{"id":"C","text":"A public routable address"},{"id":"D","text":"A broadcast address"}],"correctId":"A","rationale":"When a Windows client cannot contact a DHCP server, it auto-configures an Automatic Private IP Addressing (APIPA) address in the 169.254.0.0/16 range, which is link-local only and not routable. The loopback range is 127.0.0.0/8 (e.g., 127.0.0.1). Public addresses are assigned by IANA/ISPs and are globally routable.","optionNotes":{"B":"Loopback is 127.0.0.0/8, used to test the local TCP/IP stack","C":"169.254.x.x is private link-local, never routable on the public Internet","D":"A broadcast address targets all hosts on a subnet, not a self-assigned host IP"},"reference":"IT & Telecommunications › Loopback/APIPA addresses"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"An embassy's edge router maps many internal private IPs to a single public IP, using unique source port numbers to track each session. What is this technique called?","options":[{"id":"A","text":"PAT (Port Address Translation / NAT overload)"},{"id":"B","text":"Static one-to-one NAT"},{"id":"C","text":"DNS round-robin"},{"id":"D","text":"Proxy ARP"}],"correctId":"A","rationale":"Port Address Translation (PAT), also called NAT overload, lets many internal hosts share one public IP by differentiating sessions with unique source port numbers. Static NAT is a fixed one-to-one mapping of one private IP to one public IP, which does not conserve addresses. DNS round-robin distributes load across multiple A records and is unrelated to address translation.","optionNotes":{"B":"Static NAT is one-to-one, not many-to-one, so it does not multiplex by port","C":"DNS round-robin balances name resolution, not IP translation","D":"Proxy ARP answers ARP requests on behalf of another host, not address translation"},"reference":"IT & Telecommunications › NAT/PAT"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"The embassy is upgrading its wireless network for the strongest available security. Which standard introduces SAE (Simultaneous Authentication of Equals) to replace the pre-shared key handshake and resist offline dictionary attacks?","options":[{"id":"A","text":"WPA3"},{"id":"B","text":"WPA2"},{"id":"C","text":"WEP"},{"id":"D","text":"WPA"}],"correctId":"A","rationale":"WPA3 replaces the WPA2 4-way handshake (PSK) with SAE, a Dragonfly-based key exchange that resists offline dictionary/brute-force attacks and provides forward secrecy. WPA2 uses AES-CCMP but relies on the older PSK handshake vulnerable to capture-and-crack. WEP and the original WPA (TKIP) are deprecated and cryptographically broken.","optionNotes":{"B":"WPA2 uses the 4-way PSK handshake, not SAE","C":"WEP is obsolete and trivially cracked","D":"Original WPA used TKIP and predates SAE"},"reference":"IT & Telecommunications › Wi-Fi standards & security"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"EASY","prompt":"A technician needs to power an IP security camera over the same Ethernet cable that carries its data, with no separate power adapter. Which technology enables this?","options":[{"id":"A","text":"PoE (Power over Ethernet)"},{"id":"B","text":"USB-C Power Delivery"},{"id":"C","text":"KVM switching"},{"id":"D","text":"Link aggregation"}],"correctId":"A","rationale":"Power over Ethernet (PoE) delivers electrical power along with data over a single twisted-pair Ethernet cable, ideal for cameras, VoIP phones, and access points where running separate power is impractical. USB-C PD powers devices but is not an Ethernet/network cabling standard. KVM switching shares a keyboard/video/mouse, and link aggregation bonds multiple links for bandwidth, neither of which delivers power.","optionNotes":{"B":"USB-C PD is not carried over Ethernet cabling","C":"KVM shares console peripherals, not power over network cable","D":"Link aggregation increases bandwidth/redundancy, not power delivery"},"reference":"IT & Telecommunications › PoE"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"An embassy file server uses four disks configured so that data is striped with distributed parity, surviving the loss of any single drive. Which RAID level is this?","options":[{"id":"A","text":"RAID 5"},{"id":"B","text":"RAID 0"},{"id":"C","text":"RAID 1"},{"id":"D","text":"RAID 10"}],"correctId":"A","rationale":"RAID 5 stripes data with distributed parity across all member disks and can tolerate the failure of any one drive while remaining online. RAID 0 stripes with no parity and has zero fault tolerance. RAID 1 mirrors (no striping/parity), and RAID 10 combines mirroring and striping but does not use distributed parity.","optionNotes":{"B":"RAID 0 has no redundancy; one disk failure loses all data","C":"RAID 1 is a mirror, not striping with distributed parity","D":"RAID 10 uses mirrored stripes, not parity"},"reference":"IT & Telecommunications › RAID levels"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"HARD","prompt":"On a Windows file server, a user is a member of two groups: one group has NTFS Modify permission on a folder and the other is explicitly Denied Write. The folder is also shared with Share permission Read. When the user connects over the network, what is the effective permission?","options":[{"id":"A","text":"No write access, because an explicit Deny overrides allows and the most restrictive of share/NTFS applies"},{"id":"B","text":"Modify, because NTFS Allow permissions are cumulative"},{"id":"C","text":"Full Control, because membership in multiple groups grants the union of all rights"},{"id":"D","text":"Read/Write, because Share permissions always take precedence over NTFS"}],"correctId":"A","rationale":"An explicit Deny on NTFS overrides any Allow, so the Write Deny removes write capability regardless of the Modify grant. Additionally, when accessing over the network, the effective permission is the most restrictive combination of Share and NTFS permissions; the Share is only Read. Both rules independently block writing, so the user cannot write.","optionNotes":{"B":"Allows are cumulative, but an explicit Deny always overrides them","C":"Deny and the restrictive share/NTFS intersection prevent Full Control","D":"Over the network, the more restrictive of Share vs NTFS applies, not share precedence"},"reference":"IT & Telecommunications › Windows admin & NTFS permissions"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"An administrator wants to push a standardized desktop lockdown configuration to all workstations in an Active Directory organizational unit. Which tool is designed for this?","options":[{"id":"A","text":"Group Policy (GPO linked to the OU)"},{"id":"B","text":"DNS conditional forwarding"},{"id":"C","text":"DHCP reservations"},{"id":"D","text":"A login script copied manually to each PC"}],"correctId":"A","rationale":"Group Policy Objects (GPOs) linked to a site, domain, or organizational unit centrally enforce configuration and security settings across many AD-joined machines automatically. DNS conditional forwarding routes name queries and DHCP reservations bind IPs to MACs, neither of which manages desktop configuration. Manually copying scripts to each PC is not scalable or centrally managed.","optionNotes":{"B":"DNS conditional forwarding is for name resolution, not config enforcement","C":"DHCP reservations assign fixed IPs, not policy settings","D":"Manual per-PC copying defeats the purpose of centralized management"},"reference":"IT & Telecommunications › Active Directory/Group Policy"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"A technician runs a diagnostic that lists each router hop between the embassy and a remote host, showing latency at each step. Which utility is being used?","options":[{"id":"A","text":"tracert / traceroute"},{"id":"B","text":"nslookup"},{"id":"C","text":"ipconfig"},{"id":"D","text":"netstat"}],"correctId":"A","rationale":"Traceroute (tracert on Windows) maps the path of routers (hops) to a destination by sending packets with incrementing TTL values and recording each hop's response time. nslookup queries DNS records, ipconfig displays/refreshes local IP configuration, and netstat shows active connections and listening ports, none of which trace the hop-by-hop path.","optionNotes":{"B":"nslookup resolves DNS names, it does not map router hops","C":"ipconfig shows local interface configuration only","D":"netstat lists connections/sockets, not the route to a host"},"reference":"IT & Telecommunications › Traceroute"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"HARD","prompt":"An IPv6 address begins with the prefix FE80::/10. What type of address is this and what is its scope?","options":[{"id":"A","text":"A link-local address, valid only on the local network segment"},{"id":"B","text":"A global unicast address routable on the public Internet"},{"id":"C","text":"A unique local address (ULA) equivalent to RFC 1918 private space"},{"id":"D","text":"A multicast address for one-to-many delivery"}],"correctId":"A","rationale":"FE80::/10 is the IPv6 link-local range, automatically configured on every IPv6 interface and used only for communication on the same physical link (e.g., neighbor discovery); routers never forward it. Global unicast addresses begin with 2000::/3. Unique local addresses use FC00::/7 (commonly FD00::/8), and multicast addresses begin with FF00::/8.","optionNotes":{"B":"Global unicast uses 2000::/3, not FE80::","C":"ULA uses FC00::/7 (FD00::/8), a different prefix","D":"Multicast uses FF00::/8, not FE80::"},"reference":"IT & Telecommunications › IPv6 basics"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"EASY","prompt":"Following the CompTIA troubleshooting methodology, what is the correct FIRST step when addressing a reported IT problem?","options":[{"id":"A","text":"Identify the problem (gather information, question the user, determine scope)"},{"id":"B","text":"Establish a plan of action to resolve the problem"},{"id":"C","text":"Verify full system functionality"},{"id":"D","text":"Document findings, actions, and outcomes"}],"correctId":"A","rationale":"The CompTIA six-step troubleshooting model begins with identifying the problem by gathering information and questioning the user. Establishing a plan of action comes after a theory has been tested and confirmed. Verifying functionality and documenting are the final steps in the sequence.","optionNotes":{"B":"Planning a fix occurs after the cause is confirmed, not first","C":"Verifying functionality is near the end of the process","D":"Documentation is the final step"},"reference":"IT & Telecommunications › CompTIA troubleshooting methodology"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"HARD","prompt":"A network link is rated at 1 Gbps, but a file transfer sustains only about 400 Mbps due to congestion and latency. Which statement best distinguishes the two figures?","options":[{"id":"A","text":"1 Gbps is the bandwidth (theoretical maximum capacity); 400 Mbps is the actual throughput achieved"},{"id":"B","text":"1 Gbps is the throughput; 400 Mbps is the bandwidth"},{"id":"C","text":"Both terms mean the same thing and the difference is a measurement error"},{"id":"D","text":"400 Mbps is the bandwidth ceiling and 1 Gbps is theoretical latency"}],"correctId":"A","rationale":"Bandwidth is the maximum theoretical data-carrying capacity of a link (here 1 Gbps), while throughput is the real-world data rate actually achieved (400 Mbps), which is reduced by congestion, overhead, latency, and errors. The two are distinct, so they are not interchangeable. Latency is measured in time (ms), not bits per second.","optionNotes":{"B":"The labels are reversed; capacity is bandwidth, achieved rate is throughput","C":"They are distinct concepts, not the same","D":"Latency is a time delay, not a data rate"},"reference":"IT & Telecommunications › Bandwidth vs throughput"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"A legacy network segment reports frequent collisions, and a connected device can transmit OR receive but not both at the same time. Which condition describes this link?","options":[{"id":"A","text":"Half-duplex"},{"id":"B","text":"Full-duplex"},{"id":"C","text":"Simplex"},{"id":"D","text":"Multiplexed"}],"correctId":"A","rationale":"Half-duplex links allow communication in both directions but only one direction at a time, which is why collisions (and CSMA/CD) are associated with shared half-duplex media. Full-duplex permits simultaneous send and receive, eliminating collisions. Simplex is one-directional only, and multiplexing combines multiple signals onto one medium.","optionNotes":{"B":"Full-duplex allows simultaneous send/receive and avoids collisions","C":"Simplex is strictly one-way communication","D":"Multiplexing combines signals; it is not a duplex mode"},"reference":"IT & Telecommunications › Half/full duplex"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"An embassy is running new horizontal cabling rated to support 10GBASE-T over a full 100-meter run with improved crosstalk protection. Which copper cabling category is the minimum recommended choice?","options":[{"id":"A","text":"Cat6a"},{"id":"B","text":"Cat5e"},{"id":"C","text":"Cat3"},{"id":"D","text":"RG-6 coaxial"}],"correctId":"A","rationale":"Cat6a (augmented Category 6) supports 10GBASE-T to the full 100-meter distance with tighter alien-crosstalk specifications, making it the recommended minimum for reliable 10 Gbps copper runs. Cat6 supports 10G only to ~55 meters; Cat5e is rated for 1 Gbps. Cat3 is legacy voice/10 Mbps grade, and RG-6 is coaxial cable, not twisted-pair structured cabling.","optionNotes":{"B":"Cat5e tops out at 1 Gbps, not 10G","C":"Cat3 is legacy and supports only up to 10 Mbps/voice","D":"RG-6 is coaxial, not twisted-pair horizontal cabling"},"reference":"IT & Telecommunications › Structured cabling/Cat6/fiber"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"An application needs to store millions of static images and documents, accessed over HTTP via unique keys, with virtually unlimited scalability and rich metadata. Which storage type best fits?","options":[{"id":"A","text":"Object storage"},{"id":"B","text":"Block storage"},{"id":"C","text":"File storage (NAS share)"},{"id":"D","text":"A relational database table"}],"correctId":"A","rationale":"Object storage (e.g., S3-style) stores data as objects with unique keys and metadata in a flat namespace, accessed over HTTP(S), and scales massively, making it ideal for static assets like images and documents. Block storage presents raw volumes to a single host and is suited to databases or OS disks, not web-scale object retrieval. File storage uses a hierarchical share accessed via SMB/NFS and does not scale to billions of HTTP-addressable objects as readily.","optionNotes":{"B":"Block storage is low-level volumes for a VM/database, not HTTP key access","C":"File storage uses a directory hierarchy over SMB/NFS, less suited to massive web assets","D":"A relational table is for structured records, not large binary blobs"},"reference":"Cloud Computing › Object vs block vs file storage"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"A cloud architect deploys resources across multiple physically isolated data centers within the same metropolitan area to survive a single facility failure with low-latency replication. What is each isolated data center called?","options":[{"id":"A","text":"An Availability Zone"},{"id":"B","text":"A Region"},{"id":"C","text":"An edge location"},{"id":"D","text":"A virtual private cloud"}],"correctId":"A","rationale":"Availability Zones (AZs) are physically separate data centers within a region, each with independent power and cooling but connected by low-latency links, so spreading across AZs protects against a single facility failure. A region is a broad geographic area that contains multiple AZs. Edge locations serve cached content (CDN), and a VPC is a logically isolated network, not a physical data center.","optionNotes":{"B":"A region is the larger geographic grouping that contains multiple AZs","C":"Edge locations are CDN caching points, not full availability data centers","D":"A VPC is a logical network construct, not a physical facility"},"reference":"Cloud Computing › Regions vs availability zones"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"EASY","prompt":"An embassy public website serves users worldwide. To reduce latency, static content is cached at points of presence geographically close to visitors. Which service provides this?","options":[{"id":"A","text":"A Content Delivery Network (CDN)"},{"id":"B","text":"An auto-scaling group"},{"id":"C","text":"A relational database replica"},{"id":"D","text":"A NAT gateway"}],"correctId":"A","rationale":"A CDN caches static content at distributed edge locations near end users, reducing latency and offloading the origin server. An auto-scaling group adds/removes compute instances based on load but does not geographically cache content. A database replica improves read scalability, and a NAT gateway provides outbound Internet access for private subnets, neither of which performs edge caching.","optionNotes":{"B":"Auto-scaling adjusts compute capacity, not edge caching","C":"A DB replica scales reads, not static content delivery to edges","D":"A NAT gateway handles outbound connectivity, not caching"},"reference":"Cloud Computing › CDN"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"A team wants to run code in response to events without provisioning or managing any servers, paying only for execution time. Which model is this?","options":[{"id":"A","text":"Serverless (Functions as a Service)"},{"id":"B","text":"Infrastructure as a Service"},{"id":"C","text":"A reserved virtual machine instance"},{"id":"D","text":"A bare-metal colocation server"}],"correctId":"A","rationale":"Serverless / Functions as a Service runs event-triggered code where the provider handles all server provisioning and scaling, and you are billed only for actual execution time. IaaS still requires you to manage and pay for running VMs. A reserved VM is a committed always-on instance, and bare-metal colocation involves managing physical hardware, the opposite of serverless.","optionNotes":{"B":"IaaS requires managing and paying for VM instances","C":"A reserved instance runs continuously and is billed on commitment, not per-execution","D":"Bare-metal colocation means managing physical servers yourself"},"reference":"Cloud Computing › Serverless/functions"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"HARD","prompt":"Following least privilege, an application running on a cloud VM needs temporary credentials to read from object storage. What is the recommended IAM approach?","options":[{"id":"A","text":"Attach an IAM role to the instance so it assumes scoped, automatically rotated temporary credentials"},{"id":"B","text":"Embed a long-lived access key and secret in the application's source code"},{"id":"C","text":"Use the root/owner account credentials for the application"},{"id":"D","text":"Disable IAM and make the storage bucket publicly writable"}],"correctId":"A","rationale":"Attaching an IAM role grants the instance temporary, automatically rotated credentials scoped only to the needed actions, which follows least privilege and avoids stored secrets. Hard-coding long-lived keys risks credential leakage and rotation problems. Using root credentials violates least privilege catastrophically, and making the bucket public removes access control entirely.","optionNotes":{"B":"Embedded long-lived keys are easily leaked and rarely rotated","C":"Root credentials grant excessive privilege and break least privilege","D":"Public write access exposes data to anyone and is never appropriate"},"reference":"Cloud Computing › IAM roles/policies"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"HARD","prompt":"A cloud SLA guarantees 99.9% monthly uptime. Approximately how much downtime per month does that allow, and how does it compare to 99.99%?","options":[{"id":"A","text":"About 43 minutes/month at 99.9%, versus about 4 minutes/month at 99.99%"},{"id":"B","text":"About 7 hours/month at 99.9%, versus about 1 hour/month at 99.99%"},{"id":"C","text":"About 8 minutes/month at 99.9%, versus about 1 minute/month at 99.99%"},{"id":"D","text":"Zero downtime at 99.9%, versus zero downtime at 99.99%"}],"correctId":"A","rationale":"A 30-day month has roughly 43,200 minutes; 0.1% of that is about 43 minutes (the 99.9% or 'three nines' allowance), while 0.01% is about 4.3 minutes (99.99% or 'four nines'). Each added nine reduces allowed downtime by roughly a factor of ten. No SLA tier guarantees literally zero downtime.","optionNotes":{"B":"Those figures are far too high; 0.1% of a month is ~43 min, not 7 hours","C":"These values are roughly ten times too small","D":"No commercial SLA promises absolute zero downtime"},"reference":"Cloud Computing › SLA/uptime tiers"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"An embassy workload runs 24/7 at predictable, steady capacity for the next three years. Which pricing model typically yields the greatest savings versus paying the standard hourly rate?","options":[{"id":"A","text":"Reserved instances (committed term)"},{"id":"B","text":"On-demand instances"},{"id":"C","text":"Spot/preemptible instances for the production workload"},{"id":"D","text":"Per-request serverless billing"}],"correctId":"A","rationale":"Reserved instances offer substantial discounts (often 40-70%) in exchange for a one- or three-year commitment, making them ideal for steady, predictable, always-on workloads. On-demand pricing is the most expensive per hour and best for unpredictable bursts. Spot/preemptible instances are cheap but can be reclaimed with little notice, which is unsuitable for steady production, and serverless billing fits sporadic event-driven work rather than constant load.","optionNotes":{"B":"On-demand is the baseline highest hourly rate with no commitment discount","C":"Spot instances can be terminated anytime, risky for steady production","D":"Per-request serverless suits intermittent workloads, not constant 24/7 compute"},"reference":"Cloud Computing › Cost models (reserved vs on-demand)"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"HARD","prompt":"In a VPC, an administrator wants instance-level traffic control that is stateful (return traffic for an allowed inbound request is automatically permitted). Which construct provides this?","options":[{"id":"A","text":"A security group"},{"id":"B","text":"A network ACL (NACL)"},{"id":"C","text":"A route table"},{"id":"D","text":"An Internet gateway"}],"correctId":"A","rationale":"Security groups act as stateful virtual firewalls at the instance/ENI level: if inbound traffic is allowed, the corresponding return traffic is automatically permitted without an explicit outbound rule. Network ACLs operate at the subnet level and are stateless, requiring explicit rules for both directions. Route tables direct traffic between subnets/gateways, and an Internet gateway provides Internet connectivity, neither of which is a stateful firewall.","optionNotes":{"B":"NACLs are stateless and operate at the subnet level, requiring rules both ways","C":"A route table directs packet paths, it does not filter by stateful rules","D":"An Internet gateway enables Internet access, not instance-level filtering"},"reference":"Cloud Computing › VPC/subnets/security groups"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"An organization moves its existing on-premises application to cloud VMs with minimal changes to the application architecture to migrate quickly. Which migration strategy is this?","options":[{"id":"A","text":"Lift-and-shift (rehosting)"},{"id":"B","text":"Refactoring (re-architecting)"},{"id":"C","text":"Repurchasing (move to SaaS)"},{"id":"D","text":"Retiring the application"}],"correctId":"A","rationale":"Lift-and-shift, or rehosting, moves an application to the cloud largely as-is on IaaS VMs, prioritizing speed and minimal change over cloud optimization. Refactoring re-architects the app to use cloud-native services like serverless or managed databases. Repurchasing swaps to a SaaS product, and retiring decommissions the application entirely, none of which is a near-as-is migration.","optionNotes":{"B":"Refactoring involves significant code/architecture changes, not minimal","C":"Repurchasing replaces the app with a SaaS offering","D":"Retiring means shutting the application down, not migrating it"},"reference":"Cloud Computing › Migration strategies (lift-and-shift)"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"HARD","prompt":"A team takes a point-in-time snapshot of a block storage volume. Which statement most accurately distinguishes a snapshot from a traditional backup?","options":[{"id":"A","text":"A snapshot is a point-in-time copy tied to the storage platform (often incremental), whereas a backup is typically an independent, portable copy retained per a separate policy"},{"id":"B","text":"A snapshot and a backup are identical and interchangeable terms"},{"id":"C","text":"A snapshot always stores a full, independent copy off the platform, while a backup only records metadata"},{"id":"D","text":"A backup can only be taken while the volume is offline, but a snapshot requires the volume to be deleted first"}],"correctId":"A","rationale":"Snapshots capture the state of a volume at a moment in time and are usually incremental and dependent on the underlying storage platform, enabling fast restores within that system. Backups are generally independent, portable copies stored separately (often in different media/locations) under their own retention policy, supporting longer-term recovery and disaster scenarios. They overlap but are not identical, and snapshots are not necessarily full off-platform copies.","optionNotes":{"B":"They overlap but differ in portability, dependency, and retention","C":"This reverses the concepts; snapshots are often incremental and platform-tied","D":"Neither requires the volume offline or deleted; snapshots can be taken on live volumes"},"reference":"Cloud Computing › Snapshots vs backups"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"Incoming web requests must be distributed evenly across a pool of identical backend servers, with unhealthy servers automatically removed from rotation. Which component performs this?","options":[{"id":"A","text":"A load balancer"},{"id":"B","text":"A CDN edge cache"},{"id":"C","text":"A DNS authoritative server"},{"id":"D","text":"A storage gateway"}],"correctId":"A","rationale":"A load balancer distributes incoming traffic across multiple backend instances and uses health checks to stop routing requests to failed servers, improving availability and scalability. A CDN caches static content at the edge but does not balance application requests across a backend pool. An authoritative DNS server resolves names, and a storage gateway bridges on-prem and cloud storage, neither of which performs request distribution with health checks.","optionNotes":{"B":"A CDN caches content; it does not distribute requests across a server pool with health checks","C":"DNS resolves names and offers only crude round-robin without health awareness","D":"A storage gateway handles storage integration, not request distribution"},"reference":"Cloud Computing › Load balancing"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"EASY","prompt":"A SaaS provider serves many different customer organizations from a single shared application instance and database, logically separating each customer's data. What is this architecture called?","options":[{"id":"A","text":"Multi-tenancy"},{"id":"B","text":"Single-tenancy"},{"id":"C","text":"On-premises deployment"},{"id":"D","text":"Edge computing"}],"correctId":"A","rationale":"Multi-tenancy means a single shared application/infrastructure instance serves multiple customers (tenants) with their data logically isolated, which is the common, cost-efficient SaaS model. Single-tenancy dedicates a separate instance to each customer. On-premises deployment runs software in the customer's own data center, and edge computing pushes processing near data sources, neither of which describes shared-instance tenant isolation.","optionNotes":{"B":"Single-tenancy gives each customer a dedicated, isolated instance","C":"On-premises means hosting in the customer's own facility, not shared SaaS","D":"Edge computing concerns location of processing, not tenant sharing"},"reference":"Cloud Computing › Single vs multi-tenancy"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"An embassy IT officer downloads a software update and wants to confirm the file was not altered in transit. Which technique directly verifies the file's integrity?","options":[{"id":"A","text":"Comparing a SHA-256 hash of the file against the vendor's published hash"},{"id":"B","text":"Encrypting the file with AES-256 before opening it"},{"id":"C","text":"Storing the file on a BitLocker-encrypted drive"},{"id":"D","text":"Compressing the file into a password-protected ZIP archive"}],"correctId":"A","rationale":"Hashing produces a fixed-length digest that changes if even one bit of the file changes, so matching the computed hash to the vendor's published hash confirms integrity. Encryption protects confidentiality, not integrity, and does not detect tampering on its own.","optionNotes":{"B":"Encryption provides confidentiality, not a way to detect that content was altered.","C":"Disk encryption protects data at rest but says nothing about whether the downloaded file is intact.","D":"A password-protected archive controls access but does not verify the file matches the original."},"reference":"Cybersecurity › Hashing vs encryption (integrity)"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"During a TLS handshake, which key is used to encrypt the bulk of the actual application data after the handshake completes?","options":[{"id":"A","text":"A symmetric session key negotiated during the handshake"},{"id":"B","text":"The server's RSA private key"},{"id":"C","text":"The client's public key from its certificate"},{"id":"D","text":"The certificate authority's root signing key"}],"correctId":"A","rationale":"TLS uses asymmetric cryptography only to authenticate and securely establish a shared symmetric session key; the actual application data is then encrypted with that fast symmetric key. This hybrid model combines the security of asymmetric key exchange with the speed of symmetric encryption.","optionNotes":{"B":"The server's private key is used during key exchange/authentication, not to bulk-encrypt application data.","C":"Most TLS clients do not present certificates, and asymmetric keys are not used for bulk data encryption.","D":"The CA root key signs certificates; it is never used to encrypt session traffic."},"reference":"Cybersecurity › TLS/SSL handshake"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"Which statement best describes the role of IPsec in a site-to-site VPN connecting an embassy to the State Department network?","options":[{"id":"A","text":"It authenticates and encrypts IP packets at the network layer, securing all traffic between the two gateways"},{"id":"B","text":"It encrypts only HTTP traffic by inspecting Layer 7 application headers"},{"id":"C","text":"It replaces the need for any firewall rules between the two sites"},{"id":"D","text":"It provides encryption only for email using S/MIME envelopes"}],"correctId":"A","rationale":"IPsec operates at the network layer (Layer 3), providing authentication and encryption for IP packets, which is why it can secure all traffic flowing between two VPN gateways regardless of application. In tunnel mode it encapsulates and protects entire original IP packets between the gateways.","optionNotes":{"B":"IPsec is protocol-agnostic at Layer 3 and does not inspect Layer 7 HTTP headers.","C":"A VPN tunnel still requires firewall rules to control what traffic is permitted.","D":"S/MIME is an application-layer email standard, separate from IPsec."},"reference":"Cybersecurity › IPsec/VPN protocols"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"EASY","prompt":"An MFA policy requires a password plus a fingerprint scan. These two requirements represent which combination of authentication factors?","options":[{"id":"A","text":"Something you know and something you are"},{"id":"B","text":"Something you have and something you are"},{"id":"C","text":"Something you know and something you have"},{"id":"D","text":"Somewhere you are and something you know"}],"correctId":"A","rationale":"A password is knowledge (something you know) and a fingerprint is a biometric trait (something you are). True multifactor authentication requires factors from different categories, which this pairing satisfies.","optionNotes":{"B":"A password is not 'something you have'; it is knowledge.","C":"A fingerprint is a biometric, not a possession factor.","D":"Neither a password nor a fingerprint is a location factor."},"reference":"Cybersecurity › Types of MFA factors"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"Why is a unique random salt added to each password before hashing in a credential database?","options":[{"id":"A","text":"It ensures identical passwords produce different hashes, defeating precomputed rainbow table attacks"},{"id":"B","text":"It encrypts the password so it can be decrypted later for password recovery"},{"id":"C","text":"It compresses the hash to save storage space in the database"},{"id":"D","text":"It allows the password to be transmitted in plaintext over the network safely"}],"correctId":"A","rationale":"A unique salt per user means two users with the same password get different stored hashes, so an attacker cannot use a single precomputed rainbow table against the whole database. The salt does not need to be secret; its purpose is to force per-credential cracking effort.","optionNotes":{"B":"Hashing is one-way; salting does not make passwords decryptable for recovery.","C":"Salting adds data and does not compress the hash.","D":"Salting is unrelated to safe transmission, which requires encryption like TLS."},"reference":"Cybersecurity › Password policy & salting"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"An embassy wants access decisions based on attributes such as the user's clearance level, the data's classification, time of day, and device posture. Which access control model is designed for this?","options":[{"id":"A","text":"Attribute-Based Access Control (ABAC)"},{"id":"B","text":"Role-Based Access Control (RBAC)"},{"id":"C","text":"Discretionary Access Control (DAC)"},{"id":"D","text":"Mandatory Access Control with fixed labels only"}],"correctId":"A","rationale":"ABAC evaluates policies built from multiple attributes of the subject, resource, action, and environment, enabling fine-grained, context-aware decisions like time of day and device posture. RBAC grants access based solely on assigned roles and cannot natively factor in dynamic environmental attributes.","optionNotes":{"B":"RBAC ties permissions to roles and cannot evaluate dynamic context such as time or device state.","C":"DAC lets resource owners set permissions but is not attribute-policy driven.","D":"Pure MAC uses static security labels, not flexible multi-attribute policies."},"reference":"Cybersecurity › RBAC vs ABAC"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"An embassy requires that the employee who submits a wire payment request cannot also be the one who approves it. Which security principle does this enforce?","options":[{"id":"A","text":"Separation of duties"},{"id":"B","text":"Defense in depth"},{"id":"C","text":"Implicit deny"},{"id":"D","text":"Security through obscurity"}],"correctId":"A","rationale":"Separation of duties divides a sensitive task among multiple people so that no single individual can complete it alone, reducing fraud and error. Requiring different people to submit and approve a payment is a classic example.","optionNotes":{"B":"Defense in depth layers multiple controls; it does not specifically split a task between people.","C":"Implicit deny blocks anything not explicitly allowed; it is a firewall/ACL concept.","D":"Security through obscurity relies on hiding details, which is unrelated to task division."},"reference":"Cybersecurity › Separation of duties"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"What is the primary function of a SIEM system in an embassy security operations center?","options":[{"id":"A","text":"Aggregating and correlating log and event data from many sources to detect and alert on incidents"},{"id":"B","text":"Encrypting all data at rest across endpoints automatically"},{"id":"C","text":"Replacing antivirus by scanning files for malware signatures"},{"id":"D","text":"Issuing and revoking digital certificates for users"}],"correctId":"A","rationale":"A SIEM (Security Information and Event Management) platform centralizes logs from across the environment and correlates events to surface suspicious activity and generate alerts. It provides visibility and analysis rather than performing encryption, antivirus scanning, or certificate management.","optionNotes":{"B":"Encrypting data at rest is the job of disk/file encryption tools, not a SIEM.","C":"A SIEM consumes alerts from antivirus but does not replace endpoint malware scanning.","D":"Certificate lifecycle is handled by a PKI/CA, not a SIEM."},"reference":"Cybersecurity › SIEM"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"An embassy deploys a system that blocks emails containing strings matching Social Security number patterns from leaving the network. This is an example of which control?","options":[{"id":"A","text":"Data Loss Prevention (DLP)"},{"id":"B","text":"Intrusion Detection System (IDS)"},{"id":"C","text":"Network Address Translation (NAT)"},{"id":"D","text":"Endpoint Detection and Response (EDR)"}],"correctId":"A","rationale":"DLP inspects content in motion, at rest, and in use to detect and block unauthorized transmission of sensitive data such as SSNs or classified markings. Blocking outbound email that matches sensitive patterns is a textbook DLP function.","optionNotes":{"B":"An IDS detects attacks/intrusions but is not focused on preventing sensitive data exfiltration by content.","C":"NAT translates IP addresses and has no content awareness.","D":"EDR focuses on endpoint threat detection and response, not policy-based content blocking of data egress."},"reference":"Cybersecurity › DLP"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"In risk terminology, an unpatched web server (the weakness) could be attacked by a hacking group (the actor exploiting it). Which terms correctly label these two items?","options":[{"id":"A","text":"The unpatched server is a vulnerability; the hacking group is a threat"},{"id":"B","text":"The unpatched server is a threat; the hacking group is a vulnerability"},{"id":"C","text":"Both the server and the group are risks"},{"id":"D","text":"The unpatched server is a risk; the hacking group is an exploit"}],"correctId":"A","rationale":"A vulnerability is a weakness that can be exploited, such as an unpatched server, while a threat is the potential danger or actor that could exploit it. Risk is the likelihood and impact that results when a threat acts on a vulnerability.","optionNotes":{"B":"This reverses the definitions; the server is the weakness (vulnerability), not the threat.","C":"Risk is the combination of threat and vulnerability, not the label for either item itself.","D":"An exploit is the tool/technique used; the actor is the threat and the server is the vulnerability."},"reference":"Cybersecurity › Vulnerability vs threat vs risk"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"A vulnerability is assigned a CVSS base score of 9.4. Into which severity rating does this fall?","options":[{"id":"A","text":"Critical"},{"id":"B","text":"Medium"},{"id":"C","text":"Low"},{"id":"D","text":"Informational"}],"correctId":"A","rationale":"Under the CVSS v3 qualitative scale, scores from 9.0 to 10.0 are rated Critical, so a 9.4 is Critical and typically demands urgent remediation. The bands are Low (0.1-3.9), Medium (4.0-6.9), High (7.0-8.9), and Critical (9.0-10.0).","optionNotes":{"B":"Medium corresponds to 4.0-6.9, well below 9.4.","C":"Low corresponds to 0.1-3.9.","D":"Informational/None is for a 0.0 score, not a high numeric value."},"reference":"Cybersecurity › CVSS severity"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"EASY","prompt":"The 3-2-1 backup rule recommends keeping how many copies of data and in what arrangement?","options":[{"id":"A","text":"Three copies, on two different media types, with one copy stored offsite"},{"id":"B","text":"Three copies, all on the same server, backed up once per day"},{"id":"C","text":"Two copies, on three cloud providers, with one local copy"},{"id":"D","text":"One copy onsite, two encrypted copies, and three passwords"}],"correctId":"A","rationale":"The 3-2-1 rule states you should keep three copies of your data, on two different types of media, with at least one copy stored offsite. This protects against device failure, site disasters, and localized incidents like ransomware.","optionNotes":{"B":"Keeping all copies on one server defeats the purpose of redundancy and offsite protection.","C":"The numbers and arrangement do not match the 3-2-1 definition.","D":"The rule is about copies, media, and location, not passwords."},"reference":"Cybersecurity › 3-2-1 backup rule"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"An embassy wants to enforce encryption and remotely wipe lost smartphones that access official email, including staff-owned BYOD devices. Which solution provides this capability?","options":[{"id":"A","text":"Mobile Device Management (MDM)"},{"id":"B","text":"A host-based intrusion detection system"},{"id":"C","text":"A reverse proxy"},{"id":"D","text":"A network access translation gateway"}],"correctId":"A","rationale":"MDM platforms enforce security policies on mobile devices, including encryption requirements, passcode rules, and remote wipe of lost or stolen devices. This is essential for managing both corporate and BYOD endpoints that handle official data.","optionNotes":{"B":"A host IDS monitors for intrusions and cannot enforce mobile policy or remotely wipe phones.","C":"A reverse proxy routes inbound web traffic and does not manage device security.","D":"NAT handles address translation, unrelated to device management."},"reference":"Cybersecurity › MDM/BYOD"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"A user's browser needs to check in real time whether a presented TLS certificate has been revoked, without downloading a large list. Which mechanism does this?","options":[{"id":"A","text":"OCSP (Online Certificate Status Protocol)"},{"id":"B","text":"CRL (Certificate Revocation List) download"},{"id":"C","text":"DNSSEC validation"},{"id":"D","text":"A certificate signing request (CSR)"}],"correctId":"A","rationale":"OCSP lets a client query the certificate authority for the status of a single certificate in real time, avoiding the overhead of downloading and parsing an entire revocation list. A CRL is the alternative but requires retrieving the full list of revoked certificates.","optionNotes":{"B":"A CRL works but requires downloading the whole list, which is exactly what the question excludes.","C":"DNSSEC authenticates DNS responses, not certificate revocation status.","D":"A CSR is used to request a new certificate, not to check revocation."},"reference":"Cybersecurity › Certificate revocation (CRL/OCSP)"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"A standard user exploits a flaw to gain administrator-level rights on an embassy workstation. What is this type of attack called?","options":[{"id":"A","text":"Privilege escalation"},{"id":"B","text":"A distributed denial-of-service attack"},{"id":"C","text":"Cross-site scripting"},{"id":"D","text":"A man-in-the-middle attack"}],"correctId":"A","rationale":"Privilege escalation occurs when an attacker leverages a flaw or misconfiguration to gain higher permissions than originally granted, such as moving from a standard user to administrator. Vertical escalation specifically refers to gaining greater privilege levels.","optionNotes":{"B":"A DDoS overwhelms a service with traffic; it does not raise an account's privilege level.","C":"XSS injects scripts into web pages viewed by others, not a local privilege gain.","D":"A man-in-the-middle attack intercepts communications rather than elevating account rights."},"reference":"Cybersecurity › Privilege escalation"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"EASY","prompt":"An unauthorized person follows an employee through a badge-controlled embassy door without scanning their own credential. What is this physical security breach called?","options":[{"id":"A","text":"Tailgating"},{"id":"B","text":"Pharming"},{"id":"C","text":"Smurfing"},{"id":"D","text":"Typosquatting"}],"correctId":"A","rationale":"Tailgating (also called piggybacking) is when an unauthorized individual follows an authorized person through a secured entry point without authenticating. Mitigations include mantraps, security awareness, and not holding doors for strangers.","optionNotes":{"B":"Pharming redirects users to fraudulent websites, a network/DNS attack.","C":"Smurfing is a type of ICMP-based denial-of-service amplification attack.","D":"Typosquatting registers misspelled domains to trick users, not a physical entry attack."},"reference":"Cybersecurity › Physical security/tailgating"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"An embassy workstation is actively encrypting files and displaying a ransom note. What is the most appropriate immediate first response?","options":[{"id":"A","text":"Isolate the machine from the network to stop the spread, then notify the incident response team"},{"id":"B","text":"Immediately pay the ransom to recover the files quickly"},{"id":"C","text":"Reboot the machine repeatedly until the note disappears"},{"id":"D","text":"Run a full disk defragmentation to recover the encrypted files"}],"correctId":"A","rationale":"The first priority during an active ransomware infection is containment: disconnecting the host from the network to prevent the malware from spreading to shared drives and other systems, followed by alerting the incident response team. Paying the ransom is discouraged and does not guarantee recovery.","optionNotes":{"B":"Paying is discouraged, may be illegal in some contexts, and does not guarantee decryption.","C":"Rebooting can trigger further encryption or destroy volatile forensic evidence.","D":"Defragmentation cannot reverse encryption and may worsen recovery prospects."},"reference":"Cybersecurity › Ransomware response basics"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"An embassy firewall is configured so that all inbound traffic is denied by default and only explicitly listed ports and sources are permitted. This configuration approach is known as:","options":[{"id":"A","text":"An allowlist (default-deny) policy"},{"id":"B","text":"A blocklist (default-allow) policy"},{"id":"C","text":"Port mirroring"},{"id":"D","text":"Stateful failover"}],"correctId":"A","rationale":"An allowlist policy denies everything by default and permits only what is explicitly approved, which is the more secure posture for firewall rules. A blocklist instead allows everything except specifically denied items, leaving a larger attack surface.","optionNotes":{"B":"A blocklist defaults to allow and only blocks named items, the opposite of what is described.","C":"Port mirroring copies traffic to a monitoring port; it is not a filtering policy.","D":"Stateful failover is about high availability, not rule philosophy."},"reference":"Cybersecurity › Ports & firewall rules (allowlist)"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"EASY","prompt":"An embassy application calls an external API and receives an HTTP 404 status. What does this indicate?","options":[{"id":"A","text":"The requested resource was not found on the server"},{"id":"B","text":"The request succeeded and returned data"},{"id":"C","text":"The client is not authenticated"},{"id":"D","text":"The server encountered an internal error"}],"correctId":"A","rationale":"HTTP 404 Not Found means the server could not find the requested resource at the given URL, often due to a wrong path or a deleted resource. It is a client-side (4xx) error indicating the target does not exist.","optionNotes":{"B":"A successful response with data is indicated by 200 OK, not 404.","C":"Missing authentication is 401 Unauthorized.","D":"An internal server error is 500, a 5xx server-side code."},"reference":"Systems Integration › HTTP status codes"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"An API returns 401 for one request and 403 for another. What is the key difference between these two responses?","options":[{"id":"A","text":"401 means the client is not authenticated; 403 means it is authenticated but not authorized for the resource"},{"id":"B","text":"401 means the resource is missing; 403 means the server failed"},{"id":"C","text":"401 means too many requests; 403 means the request was malformed"},{"id":"D","text":"401 and 403 are interchangeable and mean the same thing"}],"correctId":"A","rationale":"A 401 Unauthorized indicates the request lacks valid authentication credentials, while a 403 Forbidden indicates the identity is known but lacks permission for that resource. The distinction is authentication (who you are) versus authorization (what you may access).","optionNotes":{"B":"A missing resource is 404 and a server failure is 500, not these codes.","C":"Too many requests is 429 and a malformed request is 400.","D":"They have distinct meanings around authentication versus authorization."},"reference":"Systems Integration › HTTP status codes"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"Which statement best distinguishes a JWT (JSON Web Token) from a simple API key for authenticating API requests?","options":[{"id":"A","text":"A JWT is a signed, self-contained token carrying claims that the server can verify without a database lookup, whereas an API key is an opaque identifier the server must look up"},{"id":"B","text":"A JWT must always be stored in plaintext on the server, while an API key is encrypted"},{"id":"C","text":"An API key contains digitally signed claims, while a JWT is just a random string"},{"id":"D","text":"A JWT can only be used over HTTP, while an API key requires HTTPS"}],"correctId":"A","rationale":"A JWT is a self-contained token whose signed payload carries claims (such as identity and expiry) that the server validates cryptographically, often without querying a datastore. An API key is typically an opaque random string that the server must match against stored records to determine its owner and permissions.","optionNotes":{"B":"Servers store secrets securely and do not require JWTs in plaintext; the claim is fabricated.","C":"This reverses the concepts; the JWT carries signed claims, not the API key.","D":"Both should be sent over HTTPS; transport requirement is not the distinguishing feature."},"reference":"Systems Integration › API keys vs OAuth tokens vs JWT"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"An embassy integration receives HTTP 429 responses when it sends requests too quickly to a partner API. What mechanism is the API enforcing?","options":[{"id":"A","text":"Rate limiting (throttling)"},{"id":"B","text":"Content negotiation"},{"id":"C","text":"Schema validation"},{"id":"D","text":"Connection pooling"}],"correctId":"A","rationale":"HTTP 429 Too Many Requests signals that the client has exceeded the API's allowed request rate, which is enforced by rate limiting or throttling. Clients should honor any Retry-After header and back off before retrying.","optionNotes":{"B":"Content negotiation selects response formats and does not produce 429 errors.","C":"Schema validation rejects malformed payloads, typically with a 400, not 429.","D":"Connection pooling is a client-side performance technique, not a server-enforced limit."},"reference":"Systems Integration › Rate limiting/throttling"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"A payment integration sends the same charge request twice due to a network retry, but the customer is charged only once. Which mechanism most directly prevents the duplicate charge?","options":[{"id":"A","text":"An idempotency key included with the request so the server processes identical retries only once"},{"id":"B","text":"Increasing the API rate limit to allow more requests"},{"id":"C","text":"Switching the response format from XML to JSON"},{"id":"D","text":"Adding pagination parameters to the request"}],"correctId":"A","rationale":"An idempotency key is a unique client-generated identifier the server uses to recognize a retried request and return the original result instead of performing the operation again. This makes otherwise non-idempotent operations like a charge safe to retry.","optionNotes":{"B":"Raising the rate limit affects throughput, not duplicate-processing protection.","C":"Changing the data format has no effect on whether duplicate operations are deduplicated.","D":"Pagination controls result set chunking and is unrelated to retry safety."},"reference":"Systems Integration › Idempotency keys"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"An API provider plans a breaking change to its response structure but must avoid disrupting existing embassy integrations. Which practice best addresses this?","options":[{"id":"A","text":"Introduce a new version of the API (e.g., /v2) while keeping /v1 available during a transition period"},{"id":"B","text":"Silently change the v1 response and notify clients afterward"},{"id":"C","text":"Reduce the rate limit so fewer clients are affected"},{"id":"D","text":"Switch authentication from OAuth to API keys"}],"correctId":"A","rationale":"API versioning lets a provider release breaking changes under a new version path or header while keeping the prior version operational, giving consumers time to migrate. This preserves backward compatibility and avoids breaking existing integrations.","optionNotes":{"B":"Silently changing a live version is exactly what breaks existing clients.","C":"Lowering the rate limit does not address structural breaking changes.","D":"Changing the auth scheme is unrelated to managing response-structure changes and could itself break clients."},"reference":"Systems Integration › API versioning"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"An API returns large result sets in chunks using parameters like limit and offset (or a cursor). What integration concept does this implement?","options":[{"id":"A","text":"Pagination"},{"id":"B","text":"Idempotency"},{"id":"C","text":"Content compression"},{"id":"D","text":"Load balancing"}],"correctId":"A","rationale":"Pagination breaks a large result set into smaller pages using parameters such as limit/offset or a cursor token, improving performance and reducing payload size. It lets clients retrieve data incrementally rather than all at once.","optionNotes":{"B":"Idempotency concerns safe retries, not chunking results.","C":"Compression shrinks payload bytes but does not split results into pages.","D":"Load balancing distributes traffic across servers, unrelated to result chunking."},"reference":"Systems Integration › Pagination"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"Compared with JSON, which is a genuine advantage of XML for certain enterprise integrations?","options":[{"id":"A","text":"XML supports schema validation (XSD) and namespaces, enabling strict document structure enforcement and metadata via attributes"},{"id":"B","text":"XML always produces smaller payloads than JSON"},{"id":"C","text":"XML is the only format that browsers can parse natively"},{"id":"D","text":"XML cannot represent nested or hierarchical data"}],"correctId":"A","rationale":"XML offers mature, standardized schema validation through XSD plus namespaces and attributes, which is valuable when strict structure and rich metadata are required, as in many enterprise or government systems. JSON is lighter but historically had less formal schema tooling.","optionNotes":{"B":"XML is generally more verbose than JSON, producing larger payloads.","C":"Browsers natively parse JSON via JavaScript; this claim is false.","D":"XML handles hierarchical data well; the claim is incorrect."},"reference":"Systems Integration › XML vs JSON vs CSV trade-offs"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"When is CSV typically the most appropriate format for exchanging data between two systems?","options":[{"id":"A","text":"For flat, tabular data with a uniform set of columns, such as a bulk export of records"},{"id":"B","text":"For deeply nested, hierarchical objects with varying structures"},{"id":"C","text":"For transmitting binary executables securely"},{"id":"D","text":"For enforcing a strict XSD schema with namespaces"}],"correctId":"A","rationale":"CSV excels at simple, flat, tabular datasets where every row shares the same columns, making it lightweight and widely supported for bulk exports and spreadsheet interchange. It is poorly suited to nested or hierarchical structures, which JSON or XML handle better.","optionNotes":{"B":"CSV has no native way to represent nested or variable hierarchical structures.","C":"CSV is a text format for tabular data, not a transport for binaries.","D":"Schema enforcement via XSD and namespaces is an XML feature, not CSV."},"reference":"Systems Integration › XML vs JSON vs CSV trade-offs"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"What is the primary architectural difference between an API gateway and a traditional Enterprise Service Bus (ESB)?","options":[{"id":"A","text":"An API gateway is a lightweight entry point handling routing, auth, and rate limiting for APIs, while an ESB is a heavier middleware layer focused on integrating and orchestrating many internal systems with transformation and routing"},{"id":"B","text":"An API gateway can only handle SOAP, while an ESB only handles REST"},{"id":"C","text":"An ESB encrypts data while an API gateway never can"},{"id":"D","text":"They are identical and the terms are fully interchangeable"}],"correctId":"A","rationale":"An API gateway sits at the edge to manage and secure API traffic with concerns like routing, authentication, throttling, and observability, typically for client-facing APIs. An ESB is broader middleware that connects and orchestrates many internal applications, handling message transformation, protocol mediation, and complex routing.","optionNotes":{"B":"Both can work with multiple protocols; this protocol split is incorrect.","C":"API gateways routinely terminate TLS and handle encryption; the claim is false.","D":"They serve different roles and are not interchangeable."},"reference":"Systems Integration › API gateway vs ESB"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"Two organizations exchange standardized purchase orders and invoices in a structured, machine-readable format following agreed standards like ANSI X12. This is an example of:","options":[{"id":"A","text":"Electronic Data Interchange (EDI)"},{"id":"B","text":"A webhook subscription"},{"id":"C","text":"A content delivery network"},{"id":"D","text":"A relational join"}],"correctId":"A","rationale":"EDI is the structured, standardized electronic exchange of business documents such as purchase orders and invoices between organizations, using standards like ANSI X12 or EDIFACT. It enables automated, machine-to-machine business transactions without manual re-entry.","optionNotes":{"B":"A webhook is an event callback mechanism, not a business-document interchange standard.","C":"A CDN distributes web content geographically, unrelated to document exchange.","D":"A relational join combines database tables, not an inter-organization exchange format."},"reference":"Systems Integration › EDI"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"During integration between two systems, the source field 'cust_name' must be matched to the destination field 'CustomerFullName' and a date reformatted from MM/DD/YYYY to YYYY-MM-DD. This work is best described as:","options":[{"id":"A","text":"Data mapping and transformation"},{"id":"B","text":"Load balancing"},{"id":"C","text":"Certificate pinning"},{"id":"D","text":"Horizontal scaling"}],"correctId":"A","rationale":"Data mapping defines how fields in a source system correspond to fields in a target system, and transformation converts values into the required format, such as reformatting dates. Together they reconcile differences between two systems' data structures.","optionNotes":{"B":"Load balancing distributes traffic and has nothing to do with field correspondence.","C":"Certificate pinning is a TLS trust technique, not data structure reconciliation.","D":"Horizontal scaling adds capacity by adding nodes, unrelated to field mapping."},"reference":"Systems Integration › Data mapping/transformation"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"An embassy integration must let the caller continue working immediately while a long-running report is generated, with results delivered later. Which integration style fits best?","options":[{"id":"A","text":"Asynchronous integration, where the request is accepted and the response is delivered later"},{"id":"B","text":"Synchronous integration, where the caller blocks until the full result returns"},{"id":"C","text":"A purely synchronous request-response over a single TCP socket"},{"id":"D","text":"A blocking remote procedure call that waits for completion"}],"correctId":"A","rationale":"Asynchronous integration decouples request from response so the caller is not blocked while a long operation completes; the result is delivered later via callback, polling, or a queue. This suits long-running tasks like report generation where waiting synchronously would tie up the caller.","optionNotes":{"B":"Synchronous integration forces the caller to wait, which is unsuitable for long-running work.","C":"This is just a synchronous pattern, which blocks the caller.","D":"A blocking RPC waits for completion, the opposite of what is needed."},"reference":"Systems Integration › Synchronous vs asynchronous integration"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"In a message-based integration, what is the purpose of a dead-letter queue (DLQ)?","options":[{"id":"A","text":"To hold messages that could not be processed or delivered after retries, so they can be inspected and handled separately"},{"id":"B","text":"To store the highest-priority messages for immediate processing"},{"id":"C","text":"To cache successful responses for faster repeat reads"},{"id":"D","text":"To compress messages before they enter the main queue"}],"correctId":"A","rationale":"A dead-letter queue captures messages that repeatedly fail processing or cannot be delivered, isolating them so they do not block the main queue and can be examined or reprocessed later. It is a core reliability pattern paired with retry logic.","optionNotes":{"B":"High-priority handling is the role of priority queues, not a DLQ.","C":"Caching responses is unrelated to capturing failed messages.","D":"A DLQ does not perform compression; it quarantines undeliverable messages."},"reference":"Systems Integration › Retries & dead-letter queues"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"An embassy is integrating with a REST API and wants a machine-readable contract describing its endpoints, parameters, and response schemas. Which standard provides this?","options":[{"id":"A","text":"OpenAPI (formerly Swagger) specification"},{"id":"B","text":"SMTP"},{"id":"C","text":"RADIUS"},{"id":"D","text":"NTP"}],"correctId":"A","rationale":"OpenAPI is the widely adopted standard for describing RESTful APIs in a machine-readable contract, detailing endpoints, parameters, request/response schemas, and authentication. Tools can use it to generate documentation, client SDKs, and validation.","optionNotes":{"B":"SMTP is an email transfer protocol, not an API contract format.","C":"RADIUS is a network authentication/authorization protocol.","D":"NTP synchronizes clocks and has nothing to do with API contracts."},"reference":"Systems Integration › Schema/contract (OpenAPI/WSDL)"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"An embassy receives a data feed where accented names like 'José' appear garbled as 'JosÃ©'. What is the most likely cause?","options":[{"id":"A","text":"A character encoding mismatch, such as interpreting UTF-8 bytes as a single-byte encoding like Latin-1"},{"id":"B","text":"The TLS certificate has expired"},{"id":"C","text":"The API rate limit was exceeded"},{"id":"D","text":"The JSON exceeded the maximum pagination size"}],"correctId":"A","rationale":"The classic 'mojibake' symptom where 'é' becomes 'Ã©' occurs when UTF-8 encoded bytes are decoded with a different encoding such as Latin-1/Windows-1252. Specifying and consistently using UTF-8 on both ends resolves it.","optionNotes":{"B":"An expired certificate breaks the connection or trust, not character rendering.","C":"Rate limiting returns errors like 429, not garbled characters.","D":"Pagination size limits truncate or page data; they do not corrupt character encoding."},"reference":"Systems Integration › Character encoding (UTF-8)"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"An integration repeatedly sends requests to an endpoint every 30 seconds to check whether new data is available. This data-retrieval approach is called:","options":[{"id":"A","text":"Polling"},{"id":"B","text":"A server push notification"},{"id":"C","text":"Multicasting"},{"id":"D","text":"Port forwarding"}],"correctId":"A","rationale":"Polling is when a client periodically queries a server on a schedule to check for new data or status changes. It is simple to implement but can be inefficient compared with push, since many requests may return no new data.","optionNotes":{"B":"In a push model the server initiates delivery; here the client repeatedly asks, which is polling.","C":"Multicasting delivers one stream to many receivers, unrelated to periodic checking.","D":"Port forwarding routes network traffic to an internal host, not a data-check pattern."},"reference":"Systems Integration › Polling vs push"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"EASY","prompt":"A handheld radio that can only either transmit or receive at any given moment, using a single frequency and requiring users to press a button to talk, is operating in which mode?","options":[{"id":"A","text":"Half duplex (simplex with PTT)"},{"id":"B","text":"Full duplex"},{"id":"C","text":"Multiplexed"},{"id":"D","text":"Broadcast simulcast"}],"correctId":"A","rationale":"Half-duplex communication allows transmission in both directions but only one direction at a time, which is why push-to-talk (PTT) radios require the user to release the button to hear a reply. A true single-frequency PTT radio is the classic example. Full duplex would allow simultaneous talk and listen like a telephone.","optionNotes":{"B":"Full duplex permits simultaneous two-way transmission, typically on two separate frequencies, unlike a PTT radio.","C":"Multiplexing combines multiple signals on a channel; it does not describe the talk/listen timing of a PTT radio.","D":"Simulcast refers to transmitting the same content from multiple sites, not the duplex mode of a handheld."},"reference":"Radio Systems › Simplex vs Duplex"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"MEDIUM","prompt":"In a trunked radio system serving an embassy security detail, what is the primary advantage over conventional (one-channel-per-group) radio?","options":[{"id":"A","text":"A control channel dynamically assigns talkgroups to any free RF channel, improving spectrum efficiency"},{"id":"B","text":"Each talkgroup is permanently bound to a fixed frequency for the life of the system"},{"id":"C","text":"It eliminates the need for any repeater infrastructure"},{"id":"D","text":"It guarantees full-duplex operation for every portable radio"}],"correctId":"A","rationale":"Trunked radio uses a control channel to dynamically allocate a pool of RF channels to talkgroups on demand, so many groups share fewer frequencies far more efficiently than conventional systems where each group needs its own dedicated channel. This statistical sharing increases capacity for a given amount of spectrum.","optionNotes":{"B":"That describes conventional radio; trunking specifically avoids permanent frequency-to-group binding.","C":"Trunked systems still rely on repeater/site infrastructure to provide coverage.","D":"Trunking does not inherently make portables full-duplex; most remain half-duplex PTT."},"reference":"Radio Systems › Trunked Radio"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"MEDIUM","prompt":"Two handheld radios share a frequency but are set to different CTCSS (PL) tones. What is the practical effect?","options":[{"id":"A","text":"A radio's speaker stays muted unless an incoming signal carries the matching sub-audible tone"},{"id":"B","text":"The radios automatically encrypt their voice traffic end-to-end"},{"id":"C","text":"Each radio transmits on a slightly offset frequency to avoid collisions"},{"id":"D","text":"Transmit power is doubled to overcome co-channel users"}],"correctId":"A","rationale":"CTCSS (Continuous Tone-Coded Squelch System, or PL) adds a low-frequency sub-audible tone to transmissions; a receiver only opens its squelch and unmutes when it detects the configured tone. It reduces nuisance from other users on a shared channel but provides no privacy or security, since anyone can still hear traffic by disabling tone squelch.","optionNotes":{"B":"CTCSS is not encryption; it offers no confidentiality and is trivially defeated.","C":"CTCSS does not change the carrier frequency; both radios remain co-channel.","D":"Tone squelch has no effect on transmit power."},"reference":"Radio Systems › Squelch / CTCSS"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"HARD","prompt":"Over-the-air rekeying (OTAR) is used to manage encryption keys in a secure embassy radio network. What does OTAR primarily provide?","options":[{"id":"A","text":"Remote distribution of new COMSEC keys to radios via the RF link, avoiding physical key loaders in the field"},{"id":"B","text":"A method to increase antenna gain dynamically based on distance"},{"id":"C","text":"Automatic switching between simplex and repeater modes"},{"id":"D","text":"Compression of voice traffic to reduce occupied bandwidth"}],"correctId":"A","rationale":"OTAR lets a key management facility send new or updated cryptographic keys to deployed radios over the air, eliminating the operational burden and exposure of touching each radio with a physical key-fill device. It is a core COMSEC capability that supports frequent rekeying and rapid response to a suspected key compromise.","optionNotes":{"B":"OTAR concerns key management, not antenna gain.","C":"Mode switching is unrelated to cryptographic rekeying.","D":"OTAR does not perform voice compression; vocoders handle that."},"reference":"Radio Systems › COMSEC / OTAR"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"MEDIUM","prompt":"An antenna installation shows a high VSWR (e.g., 3:1) on the feed line. What does this most directly indicate?","options":[{"id":"A","text":"An impedance mismatch causing significant reflected power back toward the transmitter"},{"id":"B","text":"That the antenna has unusually high gain"},{"id":"C","text":"That the receiver squelch is set too tight"},{"id":"D","text":"That the encryption key has expired"}],"correctId":"A","rationale":"VSWR (Voltage Standing Wave Ratio) measures how well the antenna/feed line impedance matches the transmitter; a high ratio like 3:1 means a substantial portion of forward power is reflected back instead of radiated. This wastes power and can damage the transmitter's final amplifier, so technicians tune for a VSWR close to 1:1.","optionNotes":{"B":"VSWR measures impedance match, not antenna gain.","C":"Squelch is a receiver audio function unrelated to SWR.","D":"Encryption keying has no bearing on VSWR."},"reference":"Radio Systems › Antenna / SWR"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"HARD","prompt":"Increasing a transmitter's output from 5 W to 10 W represents approximately what change in decibels?","options":[{"id":"A","text":"About +3 dB"},{"id":"B","text":"About +10 dB"},{"id":"C","text":"About +6 dB"},{"id":"D","text":"About +20 dB"}],"correctId":"A","rationale":"The decibel ratio for power is 10 * log10(P2/P1); doubling power gives 10 * log10(2) which is approximately 3 dB. As a rule of thumb, every doubling of power adds about 3 dB and every tenfold increase adds 10 dB.","optionNotes":{"B":"+10 dB corresponds to a 10x power increase (e.g., 5 W to 50 W), not doubling.","C":"+6 dB corresponds to about a 4x power increase.","D":"+20 dB corresponds to a 100x power increase."},"reference":"Radio Systems › Decibels / Power"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"MEDIUM","prompt":"When comparing satellite phone constellations, Iridium differs from INMARSAT primarily because Iridium uses:","options":[{"id":"A","text":"A low Earth orbit (LEO) constellation, giving lower latency and true polar coverage"},{"id":"B","text":"A single geostationary satellite over the equator"},{"id":"C","text":"Terrestrial cellular towers with satellite branding"},{"id":"D","text":"High-frequency skywave bouncing off the ionosphere"}],"correctId":"A","rationale":"Iridium operates a large LEO constellation, so its satellites are much closer to Earth, yielding lower latency and coverage everywhere including the poles. INMARSAT uses geostationary (GEO) satellites parked over the equator, which provide stable coverage of mid-latitudes but cannot reach the extreme polar regions and have higher latency due to the much greater distance.","optionNotes":{"B":"A single GEO satellite over the equator describes INMARSAT-style GEO service, not Iridium.","C":"Iridium relies on orbiting satellites, not terrestrial cell towers.","D":"Skywave HF propagation is unrelated to satellite phone constellations."},"reference":"Radio Systems › Iridium vs INMARSAT (LEO vs GEO)"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"HARD","prompt":"A technician notices the receiver's noise floor has risen, reducing the usable range of an embassy repeater. In link-budget terms, what does a higher noise floor do to the system?","options":[{"id":"A","text":"It raises the minimum signal level needed for an acceptable SNR, shrinking effective coverage"},{"id":"B","text":"It increases the transmitter's output power automatically"},{"id":"C","text":"It improves antenna gain at the receive site"},{"id":"D","text":"It has no effect as long as the carrier frequency is correct"}],"correctId":"A","rationale":"The noise floor sets the baseline against which signals must compete; a higher noise floor means a stronger received signal is required to maintain the same signal-to-noise ratio, effectively reducing the link margin and coverage area. Sources like local RFI, intermod, or noisy electronics can raise it, so reducing interference is key to preserving range.","optionNotes":{"B":"Noise floor is a receive-side condition and does not drive transmitter power.","C":"Antenna gain is a fixed physical property; the noise floor does not change it.","D":"A rising noise floor directly degrades SNR and range regardless of correct frequency."},"reference":"Radio Systems › Noise Floor / Link Budget"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"EASY","prompt":"An embassy phone number is written as +1-202-555-0143 in the global standard format that begins with a plus sign and country code. This format is defined by which standard?","options":[{"id":"A","text":"E.164"},{"id":"B","text":"802.11ac"},{"id":"C","text":"RFC 1918"},{"id":"D","text":"H.323 only"}],"correctId":"A","rationale":"E.164 is the ITU-T standard for international public telephone numbering, specifying the country code plus national number in a format up to 15 digits, conventionally shown with a leading plus sign. It ensures numbers are globally unique and routable across the PSTN and VoIP systems.","optionNotes":{"B":"802.11ac is a Wi-Fi standard, unrelated to telephone numbering.","C":"RFC 1918 defines private IP address ranges, not phone numbers.","D":"H.323 is a VoIP signaling protocol suite, not a numbering plan."},"reference":"PBX / VoIP › E.164 Numbering"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"EASY","prompt":"When a caller navigates an automated attendant by pressing digits on the keypad, the phone generates dual-tone signals. What are these signals called?","options":[{"id":"A","text":"DTMF (Dual-Tone Multi-Frequency) tones"},{"id":"B","text":"CTCSS tones"},{"id":"C","text":"Comfort noise"},{"id":"D","text":"Ringback tones"}],"correctId":"A","rationale":"DTMF assigns each keypad button a unique combination of one low and one high audio frequency, which the system decodes to identify the pressed digit. It is what allows touch-tone dialing and IVR/auto-attendant menu navigation.","optionNotes":{"B":"CTCSS is a sub-audible squelch tone used in two-way radio, not telephone keypads.","C":"Comfort noise is synthesized background sound during silence suppression, not a keypad signal.","D":"Ringback is the tone a caller hears while the far end rings, not a digit signal."},"reference":"PBX / VoIP › DTMF"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"A VoIP monitoring tool reports a call quality MOS of 3.6. What does MOS measure?","options":[{"id":"A","text":"A 1-to-5 score estimating perceived voice call quality"},{"id":"B","text":"The maximum number of simultaneous calls a trunk can carry"},{"id":"C","text":"The megabits per second consumed by the codec"},{"id":"D","text":"The number of failed registration attempts per hour"}],"correctId":"A","rationale":"Mean Opinion Score (MOS) rates perceived audio quality on a scale of 1 (bad) to 5 (excellent), originally from subjective listener panels and now often estimated by algorithms from metrics like latency, jitter, and loss. A MOS around 4.0 is considered toll quality, while 3.6 is acceptable but noticeably degraded.","optionNotes":{"B":"Call capacity is governed by call admission control and trunk sizing, not MOS.","C":"Codec bandwidth is measured in bits per second, not on a 1-5 quality scale.","D":"Registration failures are a signaling metric, unrelated to MOS."},"reference":"PBX / VoIP › MOS"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"Why is a Session Border Controller (SBC) typically deployed at the edge between an embassy's internal VoIP network and a carrier SIP trunk?","options":[{"id":"A","text":"To secure, normalize, and control SIP/RTP traffic crossing the network boundary, including topology hiding and protocol interworking"},{"id":"B","text":"To provide Power over Ethernet to desk phones"},{"id":"C","text":"To assign E.164 numbers to internal extensions"},{"id":"D","text":"To store voicemail messages for retrieval"}],"correctId":"A","rationale":"An SBC sits at the border of VoIP networks to enforce security (preventing toll fraud and DoS), hide internal topology, perform NAT traversal, and reconcile protocol or codec differences between the enterprise and the carrier. It effectively acts as a controlled gateway for both signaling and media at the trust boundary.","optionNotes":{"B":"PoE is delivered by network switches or injectors, not an SBC.","C":"Number assignment is a dial-plan/PBX function, not the SBC's purpose.","D":"Voicemail storage is handled by a voicemail/unified-messaging server."},"reference":"PBX / VoIP › Session Border Controller"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"HARD","prompt":"If the WAN link to the central call-control server fails, SRST (Survivable Remote Site Telephony) at the embassy branch is designed to:","options":[{"id":"A","text":"Let the local router take over basic call processing so phones keep working locally"},{"id":"B","text":"Increase the codec bitrate to compensate for the outage"},{"id":"C","text":"Reroute all calls through the SBC's voicemail system"},{"id":"D","text":"Disable the phones until the WAN is restored to prevent toll fraud"}],"correctId":"A","rationale":"SRST provides survivability by having a local gateway/router register the IP phones and handle call setup when connectivity to the centralized call manager is lost, preserving at least intra-site and emergency calling. When the WAN recovers, phones re-register with the central server and full features return.","optionNotes":{"B":"SRST is about call-control failover, not codec bitrate adjustment.","C":"SRST keeps calls working locally; it does not funnel everything into voicemail.","D":"The goal is to keep phones operational, not disable them, during an outage."},"reference":"PBX / VoIP › Failover / SRST"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"A key challenge for VoIP emergency calling (E911) compared with legacy analog lines is that:","options":[{"id":"A","text":"IP phones can move, so the system must reliably associate the device with an accurate dispatchable physical location"},{"id":"B","text":"VoIP cannot transmit DTMF digits to the PSAP"},{"id":"C","text":"Emergency numbers require E.164 formatting that VoIP cannot generate"},{"id":"D","text":"VoIP always lacks enough bandwidth to complete a voice call"}],"correctId":"A","rationale":"Because IP phones and softphones can be plugged in or roam anywhere on the network, the system cannot assume a fixed street address as legacy copper lines did; E911 implementations must track location (e.g., by switch port, subnet, or user-provided address) so responders are dispatched to the correct place. Regulations such as Kari's Law and RAY BAUM'S Act formalize these dispatchable-location requirements.","optionNotes":{"B":"VoIP can convey DTMF (in-band or via signaling), so this is not the issue.","C":"VoIP systems handle E.164 numbers normally; that is not the obstacle.","D":"A single voice call needs minimal bandwidth; bandwidth is not the core E911 problem."},"reference":"PBX / VoIP › Emergency Calling / E911"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"Configuring a dedicated voice VLAN to separate IP phone traffic from PC data traffic primarily helps because it:","options":[{"id":"A","text":"Isolates voice into its own broadcast domain so QoS and security policies can be applied to it independently"},{"id":"B","text":"Increases the analog dial tone level on each phone"},{"id":"C","text":"Removes the need for any IP addressing on the phones"},{"id":"D","text":"Forces all calls to use the G.711 codec"}],"correctId":"A","rationale":"Placing phones in a separate voice VLAN creates an independent broadcast domain, letting administrators apply prioritization (QoS) and tighter access controls to latency-sensitive voice traffic without entanglement with general PC data. It also simplifies management, addressing, and security segmentation of the converged network.","optionNotes":{"B":"VLANs are a Layer 2 concept and have nothing to do with analog dial tone levels.","C":"Phones in a voice VLAN still require IP addressing (often via DHCP).","D":"VLAN membership does not dictate which audio codec a call negotiates."},"reference":"PBX / VoIP › Voice VLAN"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"HARD","prompt":"To reliably send faxes between two embassy sites over an IP network, an administrator should use:","options":[{"id":"A","text":"T.38 fax relay, which demodulates the fax and carries it as a loss-tolerant IP protocol"},{"id":"B","text":"G.729 voice compression to shrink the fax tones"},{"id":"C","text":"Standard RTP voice with silence suppression enabled"},{"id":"D","text":"DTMF out-of-band signaling for each fax page"}],"correctId":"A","rationale":"Fax tones are highly sensitive to the packet loss and jitter of regular VoIP voice paths, so T.38 demodulates the fax signal at the gateway, transports the page data as a resilient IP protocol with redundancy, and remodulates it at the far end. This avoids the failures common when fax is forced through a lossy compressed voice (G.711/G.729) path.","optionNotes":{"B":"G.729's aggressive compression distorts fax tones and reliably breaks fax transmission.","C":"Silence suppression and ordinary voice RTP cause dropped fax pages.","D":"DTMF signaling does not carry fax image data; T.38 is the correct mechanism."},"reference":"PBX / VoIP › T.38 Fax over IP"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"Call Admission Control (CAC) is configured on the embassy's WAN-facing VoIP gateway. What problem does it address?","options":[{"id":"A","text":"It limits the number of concurrent calls so the available bandwidth is not oversubscribed, degrading all calls"},{"id":"B","text":"It blocks calls from unregistered E.164 numbers"},{"id":"C","text":"It selects the loudest codec for each conversation"},{"id":"D","text":"It encrypts the signaling channel end to end"}],"correctId":"A","rationale":"Call Admission Control caps how many simultaneous calls may traverse a constrained link, rejecting or rerouting new calls once the bandwidth budget is reached so existing calls retain acceptable quality. Without CAC, accepting one call too many can push every call on the link below an acceptable MOS.","optionNotes":{"B":"Number screening is a dial-plan/authentication function, not CAC.","C":"CAC controls call count versus bandwidth, not codec loudness selection.","D":"Signaling encryption is handled by TLS/SRTP, not CAC."},"reference":"PBX / VoIP › Call Admission Control"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"EASY","prompt":"In a relational database, a column whose value uniquely identifies each row in a table is called the:","options":[{"id":"A","text":"Primary key"},{"id":"B","text":"Foreign key"},{"id":"C","text":"Composite index hint"},{"id":"D","text":"Surrogate view"}],"correctId":"A","rationale":"A primary key uniquely identifies every row in a table and cannot be null. It is the anchor that other tables reference (via foreign keys) to establish relationships between tables.","optionNotes":{"B":"A foreign key references a primary key in another table; it does not itself guarantee uniqueness in its own table.","C":"An index hint is a query-optimizer directive, not a row identifier.","D":"A view is a saved query result, not a uniqueness constraint."},"reference":"Data Analytics › Primary vs Foreign Keys"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"MEDIUM","prompt":"You need a query that returns only the employees who have a matching record in BOTH the Employees table and the Badges table. Which SQL join is appropriate?","options":[{"id":"A","text":"INNER JOIN"},{"id":"B","text":"LEFT OUTER JOIN"},{"id":"C","text":"FULL OUTER JOIN"},{"id":"D","text":"CROSS JOIN"}],"correctId":"A","rationale":"An INNER JOIN returns only rows where the join condition is satisfied in both tables, so employees without a badge and badges without an employee are excluded. This is exactly the intersection of matching records the question requires.","optionNotes":{"B":"A LEFT OUTER JOIN would also return employees with no matching badge, padding those columns with nulls.","C":"A FULL OUTER JOIN returns unmatched rows from both tables, not just the matches.","D":"A CROSS JOIN produces the Cartesian product of all row combinations, ignoring any match condition."},"reference":"Data Analytics › SQL JOIN Types"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"EASY","prompt":"Which SQL aggregate function returns the number of rows in a result set?","options":[{"id":"A","text":"COUNT()"},{"id":"B","text":"AVG()"},{"id":"C","text":"SUM()"},{"id":"D","text":"MAX()"}],"correctId":"A","rationale":"COUNT() returns the number of rows (or non-null values of a column) matching the query. AVG and SUM compute the mean and total of a numeric column, while MAX returns the largest value, none of which give a row count.","optionNotes":{"B":"AVG() computes the arithmetic mean of a numeric column, not a row count.","C":"SUM() totals the values in a numeric column.","D":"MAX() returns the largest value in a column, not how many rows exist."},"reference":"Data Analytics › Aggregate Functions"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"MEDIUM","prompt":"An embassy's transactional badge-swipe system records thousands of small, fast inserts and lookups all day. This workload is best described as:","options":[{"id":"A","text":"OLTP (Online Transaction Processing)"},{"id":"B","text":"OLAP (Online Analytical Processing)"},{"id":"C","text":"A data warehouse star schema"},{"id":"D","text":"A batch ETL pipeline"}],"correctId":"A","rationale":"OLTP systems are optimized for many concurrent, short read/write transactions with high integrity, exactly like a badge-swipe or point-of-sale system. OLAP, by contrast, is tuned for complex analytical queries over large historical datasets and would be a poor fit for high-volume real-time inserts.","optionNotes":{"B":"OLAP is optimized for analytical aggregation over historical data, not rapid single-row transactions.","C":"A star schema is a warehouse modeling pattern used for analytics, not real-time transaction capture.","D":"A batch ETL pipeline moves and transforms data periodically; it does not describe live transaction handling."},"reference":"Data Analytics › OLTP vs OLAP"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"MEDIUM","prompt":"A report shows that as ice cream sales rise, embassy network outages also rise, with a strong positive correlation. Concluding that ice cream causes outages is a classic example of:","options":[{"id":"A","text":"Mistaking correlation for causation, ignoring a likely confounding variable (e.g., summer heat)"},{"id":"B","text":"Sampling without replacement"},{"id":"C","text":"A normalization anomaly"},{"id":"D","text":"A primary-key violation"}],"correctId":"A","rationale":"Two variables can move together without one causing the other, often because a third confounding factor (here, hot weather increasing both ice cream demand and heat-related equipment failures) drives both. Inferring causation from correlation alone is a fundamental analytical error.","optionNotes":{"B":"Sampling method has nothing to do with misinterpreting an observed correlation.","C":"Normalization anomalies are database design issues, not statistical inference errors.","D":"A primary-key violation is a data integrity error, unrelated to causal reasoning."},"reference":"Data Analytics › Correlation vs Causation"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"MEDIUM","prompt":"As part of data governance, an analyst must handle a dataset containing names, passport numbers, and home addresses. These fields are classified as:","options":[{"id":"A","text":"PII (Personally Identifiable Information) requiring access controls and minimization"},{"id":"B","text":"Metadata that needs no special handling"},{"id":"C","text":"Aggregate statistics safe for public release"},{"id":"D","text":"Denormalized keys used only for joins"}],"correctId":"A","rationale":"Personally Identifiable Information is any data that can identify a specific individual, and passport numbers, names, and addresses are textbook examples that demand safeguards such as access control, encryption, masking, and data minimization. Strong data governance policies dictate who may access PII and for what purpose.","optionNotes":{"B":"Such fields are sensitive PII, not innocuous metadata.","C":"Raw identifying records are not aggregate statistics and are unsafe to release publicly.","D":"PII fields are not merely join keys; their sensitivity is the governing concern."},"reference":"Data Analytics › Data Governance / PII"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"MEDIUM","prompt":"A document that defines each field's name, data type, allowed values, and meaning across the embassy's databases is called a:","options":[{"id":"A","text":"Data dictionary"},{"id":"B","text":"Dashboard"},{"id":"C","text":"Pivot table"},{"id":"D","text":"Query plan"}],"correctId":"A","rationale":"A data dictionary is metadata documentation that describes each data element, including its name, type, format, permitted values, and definition, providing a shared reference for consistent interpretation and governance. It helps analysts and developers understand and correctly use the data across systems.","optionNotes":{"B":"A dashboard visualizes live metrics; it does not document field definitions.","C":"A pivot table summarizes and cross-tabulates data, not its schema definitions.","D":"A query plan describes how the database engine executes a query, not field metadata."},"reference":"Data Analytics › Data Dictionary"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"HARD","prompt":"An analyst forecasts next quarter's help-desk ticket volume using historical patterns and a regression model. This activity is best categorized as:","options":[{"id":"A","text":"Predictive analytics"},{"id":"B","text":"Descriptive analytics"},{"id":"C","text":"Database normalization"},{"id":"D","text":"Data deduplication"}],"correctId":"A","rationale":"Predictive analytics uses historical data and statistical or machine-learning models to estimate future outcomes, such as forecasting upcoming ticket volume. Descriptive analytics, by contrast, only summarizes what has already happened without projecting forward.","optionNotes":{"B":"Descriptive analytics reports past/current state; it does not forecast future values.","C":"Normalization is a database design process, not an analytical forecasting method.","D":"Deduplication is a data-cleaning step, unrelated to forecasting."},"reference":"Data Analytics › Descriptive vs Predictive"}
] as const;
